import{c as a,Q as e,j as r,m as n}from"./chunks/framework.DpF7k2f3.js";const m=JSON.parse('{"title":"第5章 LLM呼び出しとプロンプトエンジニアリング","description":"","frontmatter":{"outline":"deep"},"headers":[],"relativePath":"ja/part2-fundamentals/chapter5.md","filePath":"ja/part2-fundamentals/chapter5.md"}'),o={name:"ja/part2-fundamentals/chapter5.md"};function l(s,t,p,i,c,d){return e(),r("div",null,[...t[0]||(t[0]=[n('<h1 id="第5章-llm呼び出しとプロンプトエンジニアリング" tabindex="-1">第5章 LLM呼び出しとプロンプトエンジニアリング <a class="header-anchor" href="#第5章-llm呼び出しとプロンプトエンジニアリング" aria-label="Permalink to &quot;第5章 LLM呼び出しとプロンプトエンジニアリング&quot;">​</a></h1><h2 id="本章で学べること" tabindex="-1">本章で学べること <a class="header-anchor" href="#本章で学べること" aria-label="Permalink to &quot;本章で学べること&quot;">​</a></h2><p>おめでとうございます！やっと本当のことができます！</p><p>前面几章我们聊了不少「虚」的内容——行业认知、入门路线、工程基礎。この章から、AIアプリ開発の<strong>コア技術領域</strong>に足を踏み入れます。</p><p>この章は本の最もコアな技術章の一つです。原来的内容讲了些基础技巧，说实话有点浅——就像是教你「筷子の使い方」を教えるが、「滚动する肉丸子怎么夹」までは教えてくれない那种。我会给你们补上这些实战中真正有用的东西。</p><p>读完这章，你能带走：</p><ul><li><strong>磐石一样的API呼び出し</strong>：调通就行不够，还要能扛住高并发、处理流式输出、在模型翻车时优雅降级</li><li><strong>系统的なプロンプト方法論</strong>：不是背技巧，而是理解为什么这样写有效，以及什么时候该用什么技巧</li><li><strong>本番급構造化出力</strong>：JSON Schema怎么做、多级嵌套怎么搞、信息抽出pipeline怎么搭</li><li><strong>贤いコンテキスト管理</strong>：对话状态机、意図识别、スロット填充——让AI真正「懂」用户</li><li><strong>本当のコスト管理</strong>：不是理论，是一个月烧了多少钱、怎么砍到一半的经验</li><li><strong>坑踩の血涙史</strong>：踩过的坑、不想让你再踩一遍</li></ul><hr><blockquote><p><strong>全文の翻訳は後日公開予定、しばらくお待ちください。中文版は今すぐ読めます。</strong></p><p>中文原文：<a href="/jumpstart-ai/zh/part2-fundamentals/chapter5.html">中文版阅读</a></p></blockquote>',9)])])}const _=a(o,[["render",l]]);export{m as __pageData,_ as default};
